import{_ as e,o as d,c as a,a2 as l}from"./chunks/framework.B72_uj9U.js";const x=JSON.parse('{"title":"模板与工具总览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/templates/index.md","filePath":"zh/templates/index.md"}'),r={name:"zh/templates/index.md"};function n(i,t,s,c,h,o){return d(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="模板与工具总览" tabindex="-1">模板与工具总览 <a class="header-anchor" href="#模板与工具总览" aria-label="Permalink to &quot;模板与工具总览&quot;">​</a></h1><p>本节收录了供应链六大尽职调查支柱所需的实用文件模板，涵盖政策、问卷、清单、访谈问题库和操作表单。所有模板均需根据企业实际情况、所在司法管辖区法律要求及客户标准进行调整，<strong>不构成法律建议</strong>。</p><div class="tip custom-block"><p class="custom-block-title">使用说明</p><ul><li>模板中 <code>[方括号]</code> 内的内容为需要根据实际情况填写或替换的占位符</li><li>相关标准与法规随时更新，使用前请核实当前有效版本</li><li>涉及重大法律义务的文件（如政策条款、合同附件）建议在法律顾问指导下定稿</li><li>所有问卷和清单均可拆分为单独文件或集成至供应商门户系统使用</li></ul></div><h2 id="模板目录" tabindex="-1">模板目录 <a class="header-anchor" href="#模板目录" aria-label="Permalink to &quot;模板目录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>主要用途</th><th>所涉支柱</th><th>典型使用方</th></tr></thead><tbody><tr><td><a href="./supplier-code.html">供应商行为准则（SCoC）</a></td><td>附于采购合同；新供应商准入必签文件</td><td>全部六大支柱</td><td>采购/合规</td></tr><tr><td><a href="./saq.html">供应商自评问卷（SAQ）</a></td><td>年度供应商评估；准入审查</td><td>全部六大支柱</td><td>合规/ESG</td></tr><tr><td><a href="./audit-checklist.html">审核前文件请求清单</a></td><td>各类审核前30天发出；告知供应商需准备的材料</td><td>各支柱专项</td><td>审核员/审核委托方</td></tr><tr><td><a href="./interview-questions.html">访谈问题库</a></td><td>工人保密访谈；管理层访谈；各专项审核访谈</td><td>CSR、Ethics、Security、IP</td><td>审核员</td></tr><tr><td><a href="./forms.html">操作表单</a></td><td>日常合规运营所需的填报表单</td><td>Ethics、DD</td><td>采购/合规/员工</td></tr><tr><td><a href="./policies.html">政策模板</a></td><td>建立内部合规政策体系；对供应商展示合规承诺</td><td>Ethics为主，跨支柱</td><td>合规/法务/管理层</td></tr></tbody></table><hr><h2 id="六大支柱与模板覆盖矩阵" tabindex="-1">六大支柱与模板覆盖矩阵 <a class="header-anchor" href="#六大支柱与模板覆盖矩阵" aria-label="Permalink to &quot;六大支柱与模板覆盖矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>支柱</th><th style="text-align:center;">行为准则</th><th style="text-align:center;">SAQ</th><th style="text-align:center;">审核清单</th><th style="text-align:center;">访谈问题</th><th style="text-align:center;">操作表单</th><th style="text-align:center;">政策模板</th></tr></thead><tbody><tr><td>① 社会责任（CSR）</td><td style="text-align:center;">✅ §1</td><td style="text-align:center;">✅ B节</td><td style="text-align:center;">✅ CSR清单</td><td style="text-align:center;">✅ 工人/管理层</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>② 环境合规（Env）</td><td style="text-align:center;">✅ §2</td><td style="text-align:center;">✅ C节</td><td style="text-align:center;">✅ 环境清单</td><td style="text-align:center;">✅ EHS访谈</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>③ 供应链安全（Security）</td><td style="text-align:center;">✅ §4</td><td style="text-align:center;">✅ E节</td><td style="text-align:center;">✅ 安全清单</td><td style="text-align:center;">✅ IT访谈</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>④ 知识产权（IP）</td><td style="text-align:center;">✅ §5</td><td style="text-align:center;">✅ F节</td><td style="text-align:center;">✅ IP清单</td><td style="text-align:center;">✅ IP访谈</td><td style="text-align:center;">✅ IP事件报告</td><td style="text-align:center;">—</td></tr><tr><td>⑤ 商业道德与财务（Ethics）</td><td style="text-align:center;">✅ §3</td><td style="text-align:center;">✅ D/G节</td><td style="text-align:center;">✅ 道德清单</td><td style="text-align:center;">✅ 财务/合规访谈</td><td style="text-align:center;">✅ COI/礼品/制裁</td><td style="text-align:center;">✅ 四项政策</td></tr><tr><td>⑥ 矿产溯源（Minerals）</td><td style="text-align:center;">✅ §6</td><td style="text-align:center;">✅ H节</td><td style="text-align:center;">✅ 含于道德清单</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ 矿产申报表</td><td style="text-align:center;">—</td></tr></tbody></table><hr><h2 id="快速导航-按场景选择模板" tabindex="-1">快速导航：按场景选择模板 <a class="header-anchor" href="#快速导航-按场景选择模板" aria-label="Permalink to &quot;快速导航：按场景选择模板&quot;">​</a></h2><p><strong>新供应商准入时：</strong> → <a href="./supplier-code.html">供应商行为准则</a>（要求签署后附于合同） → <a href="./saq.html">SAQ</a>（要求填写A+B+D节，高风险填写全部）</p><p><strong>年度常规评估时：</strong> → <a href="./saq.html">SAQ</a>（每年更新，低风险供应商可简化填写B+D+G节）</p><p><strong>现场审核前30天：</strong> → <a href="./audit-checklist.html">审核前文件请求清单</a>（按审核类型选择对应清单） → <a href="./interview-questions.html">访谈问题库</a>（按访谈对象选择对应问题）</p><p><strong>发现违规问题后：</strong> → <a href="./forms.html">操作表单</a> → 整改行动计划（CAP）模板</p><p><strong>建立内部合规政策体系时：</strong> → <a href="./policies.html">政策模板</a>（反贿赂、礼品招待、利益冲突、举报人保护）</p>',15)])])}const y=e(r,[["render",n]]);export{x as __pageData,y as default};
